import{c as n,Q as s,j as p,m as e}from"./chunks/framework.BI6u8GL6.js";const h=JSON.parse('{"title":"架构概览","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/architecture.md","filePath":"zh/guide/architecture.md","lastUpdated":1783201272000}'),t={name:"zh/guide/architecture.md"};function l(i,a,c,r,o,d){return s(),p("div",null,[...a[0]||(a[0]=[e(`<h1 id="架构概览" tabindex="-1">架构概览 <a class="header-anchor" href="#架构概览" aria-label="Permalink to &quot;架构概览&quot;">​</a></h1><p>本文档描述 MyJpa-Plus 的内部架构，包括模块关系、数据流和安全防御层。</p><h2 id="模块地图" tabindex="-1">模块地图 <a class="header-anchor" href="#模块地图" aria-label="Permalink to &quot;模块地图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>com.zsubera.jpa</span></span>
<span class="line"><span>├── spec/              # 查询规范构建器（核心）</span></span>
<span class="line"><span>│   ├── SFunction        — 可序列化函数式接口，用于 Lambda 属性提取</span></span>
<span class="line"><span>│   ├── QuerySpec        — 主入口（实现 Specification&amp;lt;T&amp;gt; + ConditionBuilder）</span></span>
<span class="line"><span>│   ├── SubQuerySpec     — EXISTS/IN 子查询构建器（立即求值）</span></span>
<span class="line"><span>│   ├── CteSpec          — CTE 构建器（原生 SQL）</span></span>
<span class="line"><span>│   ├── ConditionBuilder — 40+ 默认条件方法（延迟求值）</span></span>
<span class="line"><span>│   ├── ConditionNode    — Sealed AST 层级（11 种节点类型）</span></span>
<span class="line"><span>│   ├── NodeResolver     — AST → JPA Predicate 解析器</span></span>
<span class="line"><span>│   ├── PredicateHelper  — 共享静态谓词构建器</span></span>
<span class="line"><span>│   ├── FunctionWhitelist — 函数白名单（启动期 ConcurrentHashMap → 冻结快照）</span></span>
<span class="line"><span>│   ├── Spec             — Specification 组合工具类（and/or/not 静态方法）</span></span>
<span class="line"><span>│   ├── QueryAggregates  — count/sum/avg/max/min 表达式工厂</span></span>
<span class="line"><span>│   ├── JoinGroup / OrJoinGroup / OrGroup / NotGroup — 条件分组构建器</span></span>
<span class="line"><span>│   ├── BulkConditionSupport — 批量操作条件方法接口</span></span>
<span class="line"><span>│   └── QueryHavingSupport / QueryConditionSupport / QueryCompositionSupport</span></span>
<span class="line"><span>│       / QuerySubQuerySupport / QueryJoinSupport / QueryAggregateSupport</span></span>
<span class="line"><span>│       / QueryOrderBySupport — QuerySpec 拆分辅助类</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── update/            # 批量操作</span></span>
<span class="line"><span>│   ├── UpdateSpec       — 批量 UPDATE 构建器</span></span>
<span class="line"><span>│   ├── DeleteSpec       — 批量 DELETE 构建器</span></span>
<span class="line"><span>│   ├── MergeSpec        — UPSERT/MERGE 构建器（4 种方言 + 多行批处理）</span></span>
<span class="line"><span>│   ├── AbstractBulkOperationSpec — 批量操作条件树和行数限制检查</span></span>
<span class="line"><span>│   ├── OrConditionBuilder — OR 条件组构建器</span></span>
<span class="line"><span>│   ├── BulkTransactionHelper — 共享事务管理工具</span></span>
<span class="line"><span>│   ├── AuditUtils       — 审计日志和调用栈提取</span></span>
<span class="line"><span>│   ├── DialectDetector  — 从 EntityManager 自动检测数据库方言</span></span>
<span class="line"><span>│   ├── DialectStrategy  — 方言特定 UPSERT SQL 生成 SPI</span></span>
<span class="line"><span>│   ├── AbstractDialectStrategy — 共享转义逻辑</span></span>
<span class="line"><span>│   ├── MysqlDialect / PostgresDialect / OracleDialect / SqlServerDialect</span></span>
<span class="line"><span>│   └── EntityFieldExtractor — 反射实体字段 → 列名/值对</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── template/          # 查询执行与缓存</span></span>
<span class="line"><span>│   ├── MyJpaTemplate    — 主查询/批量模板（Spring Bean）</span></span>
<span class="line"><span>│   ├── MyJpaTemplateOperations — 模板操作接口（Lambda 查询重载）</span></span>
<span class="line"><span>│   ├── QueryCacheManager — 基于 ConcurrentHashMap 的 TTL 缓存（实现 CacheAdapter）</span></span>
<span class="line"><span>│   ├── CacheAdapter     — 可插拔缓存后端 SPI</span></span>
<span class="line"><span>│   ├── CacheInvalidationListener — 实体修改后自动驱逐缓存</span></span>
<span class="line"><span>│   ├── BulkOperationTemplate — 带事务管理的批量执行</span></span>
<span class="line"><span>│   ├── BatchSaveTemplate — 带 flush/clear 循环的批量持久化/合并</span></span>
<span class="line"><span>│   ├── KeysetPaginationHelper — Keyset（游标）分页辅助</span></span>
<span class="line"><span>│   ├── QueryBuildHelper — 查询构建辅助（Specification 合并、count 查询）</span></span>
<span class="line"><span>│   └── DeepPaginationGuard — 深度分页保护</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── projection/        # DTO 与 Tuple 投影（已集成到 QuerySpec）</span></span>
<span class="line"><span>│   └── QueryProjectionSupport — 通过 MyJpaTemplate 执行 select()/selectAs()/asDto()</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── repository/        # 扩展 Spring Data Repository</span></span>
<span class="line"><span>│   ├── MyJpaRepository   — 带 Lambda DSL 的 Repository 接口</span></span>
<span class="line"><span>│   ├── DefaultMyJpaRepository — 带软删除的基础实现</span></span>
<span class="line"><span>│   ├── MyJpaRepositoryFactoryBean — 自定义 RepositoryFactoryBean</span></span>
<span class="line"><span>│   ├── SoftDeleteContext  — @IgnoreSoftDelete 的 ThreadLocal 栈</span></span>
<span class="line"><span>│   ├── EntityManagerHelper / EntityManagerResolver — 多数据源解析器</span></span>
<span class="line"><span>│   ├── IgnoreSoftDeleteAdvisor — @IgnoreSoftDelete 的 AOP 切面</span></span>
<span class="line"><span>│   └── OptimisticLockRetryAdvisor — @RetryOnOptimisticLock 的 AOP 切面</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── softdelete/        # 软删除功能</span></span>
<span class="line"><span>│   ├── SoftDeleteHelper  — 软删除字段/注解/Specification 缓存</span></span>
<span class="line"><span>│   └── SoftDeleteBulkExecutor — 通过原生 SQL / CriteriaUpdate 批量删除</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── annotation/        # 自定义注解</span></span>
<span class="line"><span>│   ├── @SoftDelete       — 标记字段为软删除标志</span></span>
<span class="line"><span>│   ├── @IgnoreSoftDelete — 禁用自动软删除过滤</span></span>
<span class="line"><span>│   ├── @Encrypt          — AES/GCM 透明加密</span></span>
<span class="line"><span>│   ├── @Mask             — JSON 输出脱敏</span></span>
<span class="line"><span>│   └── @RetryOnOptimisticLock — 指数退避重试的 AOP 注解</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── converter/         # 类型转换器</span></span>
<span class="line"><span>│   ├── @CodeEnum / @CodeEnumValue — 基于编码的枚举注解</span></span>
<span class="line"><span>│   ├── CodeEnumType      — 基于编码的枚举的 Hibernate UserType</span></span>
<span class="line"><span>│   ├── CodeEnumHelper    — 枚举编码解析辅助</span></span>
<span class="line"><span>│   ├── EncryptConverter  — AES/GCM AttributeConverter</span></span>
<span class="line"><span>│   ├── EncryptionKeyManager — PBKDF2 密钥派生，多版本轮换</span></span>
<span class="line"><span>│   └── MaskSerializer    — @Mask 的 Jackson 序列化器</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── monitor/           # SQL 监控</span></span>
<span class="line"><span>│   ├── SlowQueryDataSourceProxy — 基于 JDBC 代理的慢查询检测</span></span>
<span class="line"><span>│   ├── SlowQueryDataSourceProxyPostProcessor — DataSource 后处理代理</span></span>
<span class="line"><span>│   ├── QueryMetricsCollector — 单例指标（计数、平均、最大）</span></span>
<span class="line"><span>│   ├── SqlSlowQueryInterceptor — Hibernate StatementInspector 慢查询检测（已废弃）</span></span>
<span class="line"><span>│   ├── SqlSanitizer     — 从 SQL 日志中移除敏感数据</span></span>
<span class="line"><span>│   └── SlowQueryListener — 慢查询事件监听接口</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── autoconfigure/     # Spring Boot 自动配置</span></span>
<span class="line"><span>│   ├── MyJpaPlusAutoConfiguration — 主 @AutoConfiguration</span></span>
<span class="line"><span>│   ├── MyJpaPlusGlobalConfig — 全局配置 Bean</span></span>
<span class="line"><span>│   ├── MyJpaPlusProperties — @ConfigurationProperties</span></span>
<span class="line"><span>│   ├── GlobalConfigHolder — 带 volatile 字段的集中配置</span></span>
<span class="line"><span>│   ├── EnvironmentHelper — 环境检测工具</span></span>
<span class="line"><span>│   └── SoftDeleteFilterBean — 软删除 JPA Specification 注入</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── codegen/           # 代码生成</span></span>
<span class="line"><span>│   └── EntityCodeGenerator — 从表元数据生成 JPA 实体源码</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── exception/         # 自定义异常</span></span>
<span class="line"><span>│   ├── MyJpaPlusException — 带 ErrorCode + 上下文清理的基础异常</span></span>
<span class="line"><span>│   ├── QueryBuildException / BulkOperationException / DataAccessException</span></span>
<span class="line"><span>│   └── SecurityViolationException / TimeoutException</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── util/             # 共享工具类</span></span>
<span class="line"><span>    ├── LambdaUtils        — SerializedLambda → 属性名提取</span></span>
<span class="line"><span>    ├── IdentifierValidator — SQL 标识符验证 + Unicode 同形字符检测</span></span>
<span class="line"><span>    ├── InClauseBuilder    — IN/NOT IN 子句自动分批</span></span>
<span class="line"><span>    ├── SampledEvictionCache — 基于 ConcurrentHashMap 的采样驱逐缓存</span></span>
<span class="line"><span>    ├── CacheEvictionHelper — L1 缓存选择性驱逐</span></span>
<span class="line"><span>    ├── PageableHelper     — 分页参数辅助工具</span></span>
<span class="line"><span>    └── EntityClassResolver / StringHelper / EntityGraphHelper</span></span></code></pre></div><h2 id="数据流-lambda-查询执行" tabindex="-1">数据流：Lambda 查询执行 <a class="header-anchor" href="#数据流-lambda-查询执行" aria-label="Permalink to &quot;数据流：Lambda 查询执行&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户代码                    库实现                          JPA 提供者</span></span>
<span class="line"><span>─────────                   ───────                        ────────────</span></span>
<span class="line"><span>repository.findAll(s -&gt;     QuerySpec.of(consumer)</span></span>
<span class="line"><span>  s.eq(User::getName,       │</span></span>
<span class="line"><span>    &quot;John&quot;)                 │</span></span>
<span class="line"><span>                            │ LambdaUtils.resolveProperty(User::getName)</span></span>
<span class="line"><span>                            │ → SerializedLambda → &quot;name&quot;</span></span>
<span class="line"><span>                            │</span></span>
<span class="line"><span>                            │ QuerySpec.eq(&quot;name&quot;, &quot;John&quot;)</span></span>
<span class="line"><span>                            │ → 追加 SimpleNode 到条件列表</span></span>
<span class="line"><span>                            │</span></span>
<span class="line"><span>                            │ QuerySpec.toPredicate(root, cb, query)</span></span>
<span class="line"><span>                            │ → NodeResolver.resolve(conditionTree)</span></span>
<span class="line"><span>                            │ → 递归遍历 ConditionNode 树</span></span>
<span class="line"><span>                            │ → SimpleNode.resolve() → cb.equal(root.get(&quot;name&quot;), &quot;John&quot;)</span></span>
<span class="line"><span>                            │</span></span>
<span class="line"><span>                            │ 返回 JPA Predicate</span></span>
<span class="line"><span>                            │</span></span>
<span class="line"><span>                            │ JPA CriteriaQuery.where(predicate)</span></span>
<span class="line"><span>                            └──────────────────────────────────→ SELECT * FROM users WHERE name = &#39;John&#39;</span></span></code></pre></div><h2 id="数据流-单行-upsert-执行" tabindex="-1">数据流：单行 UPSERT 执行 <a class="header-anchor" href="#数据流-单行-upsert-执行" aria-label="Permalink to &quot;数据流：单行 UPSERT 执行&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MergeSpec.withEntity(user)</span></span>
<span class="line"><span>  .onConflict(User::getEmail)</span></span>
<span class="line"><span>  .updateOnConflict(User::getName)</span></span>
<span class="line"><span>  .execute(em)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── DialectDetector.detectDialect(em)</span></span>
<span class="line"><span>    │   ├── 优先级 1: JDBC URL 属性</span></span>
<span class="line"><span>    │   ├── 优先级 2: Connection.getMetaData().getDatabaseProductName()</span></span>
<span class="line"><span>    │   ├── 优先级 3: Hibernate Session 反射</span></span>
<span class="line"><span>    │   └── 优先级 4: 系统属性 myjpa-plus.dialect</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── DialectStrategy.buildUpsertSql(...)</span></span>
<span class="line"><span>    │   ├── MysqlDialect:     INSERT INTO t (...) VALUES (...) ON DUPLICATE KEY UPDATE col = VALUES(col)</span></span>
<span class="line"><span>    │   ├── PostgresDialect:  INSERT INTO t (...) VALUES (...) ON CONFLICT (...) DO UPDATE SET col = EXCLUDED.col</span></span>
<span class="line"><span>    │   ├── OracleDialect:    MERGE INTO t USING (SELECT ? AS col FROM DUAL) ON (...) WHEN NOT MATCHED ...</span></span>
<span class="line"><span>    │   └── SqlServerDialect: MERGE INTO t USING (VALUES (?)) AS new_row(col) ON (...) WHEN NOT MATCHED ...</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── em.createNativeQuery(sql).executeUpdate()</span></span></code></pre></div><h2 id="数据流-多行批量-upsert" tabindex="-1">数据流：多行批量 UPSERT <a class="header-anchor" href="#数据流-多行批量-upsert" aria-label="Permalink to &quot;数据流：多行批量 UPSERT&quot;">​</a></h2><p>当 <code>MergeSpec.executeBatch()</code> 通过 <code>supportsBatchUpsert()</code> 检测到方言支持批量模式时：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MergeSpec.executeBatch([user1, user2, user3], em)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── DialectStrategy.supportsBatchUpsert()? → true</span></span>
<span class="line"><span>  │   ├── MysqlDialect:     true</span></span>
<span class="line"><span>  │   └── PostgresDialect:  true</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── EntityFieldExtractor.extractFieldValues() 每个实体</span></span>
<span class="line"><span>  │   → [user1: (name→&quot;A&quot;, email→&quot;a@x&quot;), user2: (name→&quot;B&quot;, email→&quot;b@x&quot;), ...]</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── DialectStrategy.buildBatchUpsertSql(...)</span></span>
<span class="line"><span>  │   ├── MysqlDialect:</span></span>
<span class="line"><span>  │   │     INSERT INTO t (name, email) VALUES (?, ?), (?, ?), (?, ?)</span></span>
<span class="line"><span>  │   │     ON DUPLICATE KEY UPDATE name = VALUES(name)</span></span>
<span class="line"><span>  │   ├── PostgresDialect:</span></span>
<span class="line"><span>  │   │     INSERT INTO t (name, email) AS _new VALUES (?, ?), (?, ?), (?, ?)</span></span>
<span class="line"><span>  │   │     ON CONFLICT (email) DO UPDATE SET name = _new.name</span></span>
<span class="line"><span>  │   └── （不支持批量模式的方言回退到逐行循环）</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  └── em.createNativeQuery(sql).executeUpdate()</span></span>
<span class="line"><span>     → N 行仅 1 次网络往返（逐行模式需 N 次）</span></span></code></pre></div><h2 id="安全防御层" tabindex="-1">安全防御层 <a class="header-anchor" href="#安全防御层" aria-label="Permalink to &quot;安全防御层&quot;">​</a></h2><p>库实现了纵深防御，包含多个安全层：</p><h3 id="第-1-层-输入验证-信任边界" tabindex="-1">第 1 层：输入验证（信任边界） <a class="header-anchor" href="#第-1-层-输入验证-信任边界" aria-label="Permalink to &quot;第 1 层：输入验证（信任边界）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户 Lambda 引用</span></span>
<span class="line"><span>  → LambdaUtils.resolveProperty()</span></span>
<span class="line"><span>    → IdentifierValidator.validateColumnName()</span></span>
<span class="line"><span>      → 正则: ^[a-zA-Z_][a-zA-Z0-9_]*$（ASCII）或 Unicode 模式</span></span>
<span class="line"><span>      → Unicode 同形字符检测（西里尔字母、希腊字母、亚美尼亚字母、全角字符）</span></span>
<span class="line"><span>      → 最大长度: 128 字符</span></span></code></pre></div><h3 id="第-2-层-函数白名单-代码注入防御" tabindex="-1">第 2 层：函数白名单（代码注入防御） <a class="header-anchor" href="#第-2-层-函数白名单-代码注入防御" aria-label="Permalink to &quot;第 2 层：函数白名单（代码注入防御）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>QuerySpec.func(field, &quot;functionName&quot;, params...)</span></span>
<span class="line"><span>  → 三层验证:</span></span>
<span class="line"><span>    1. SAFE_FIELD_NAME_PATTERN 正则</span></span>
<span class="line"><span>    2. SAFE_FUNCTION_NAMES 集合（CONCAT、COALESCE、IFNULL 等）</span></span>
<span class="line"><span>    3. BOOLEAN_FUNCTION_NAMES 集合（IS_NULL、IS_EMPTY 等）</span></span>
<span class="line"><span>  → WHITELIST_ENFORCED = true（硬编码，不可禁用）</span></span></code></pre></div><h3 id="第-3-层-sql-注入检测-cte-模块" tabindex="-1">第 3 层：SQL 注入检测（CTE 模块） <a class="header-anchor" href="#第-3-层-sql-注入检测-cte-模块" aria-label="Permalink to &quot;第 3 层：SQL 注入检测（CTE 模块）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CteSpec.as(sql)</span></span>
<span class="line"><span>  → CTE 名称的保留字验证</span></span>
<span class="line"><span>  → 危险关键词检测（DROP、TRUNCATE、GRANT 等），带词边界匹配</span></span>
<span class="line"><span>  → SQL 注入模式检测（注释、分号、UNION SELECT、WAITFOR DELAY）</span></span>
<span class="line"><span>  → 未绑定参数检测</span></span>
<span class="line"><span>  → strictMode = true（硬编码，不可禁用）</span></span></code></pre></div><h3 id="第-4-层-like-通配符转义" tabindex="-1">第 4 层：LIKE 通配符转义 <a class="header-anchor" href="#第-4-层-like-通配符转义" aria-label="Permalink to &quot;第 4 层：LIKE 通配符转义&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>QuerySpec.like(field, &quot;pattern%_&quot;)</span></span>
<span class="line"><span>  → PredicateHelper.escapeLikeWildcards()</span></span>
<span class="line"><span>    → 转义顺序: \\ → \\\\, 然后 _ → \\_, 然后 % → \\%</span></span>
<span class="line"><span>    → LIKE 转义字符: \\</span></span></code></pre></div><h3 id="第-5-层-数据清理-输出" tabindex="-1">第 5 层：数据清理（输出） <a class="header-anchor" href="#第-5-层-数据清理-输出" aria-label="Permalink to &quot;第 5 层：数据清理（输出）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MyJpaPlusException.toString()</span></span>
<span class="line"><span>  → 正则检测: password=, token=, key=, secret=, credential=, ssn, credit_card</span></span>
<span class="line"><span>  → 替换为 ***（词边界断言防止 &quot;primaryKey&quot; 误报）</span></span>
<span class="line"><span>  → 截断至 200 字符</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SqlSanitizer.sanitize(sql)</span></span>
<span class="line"><span>  → 移除: 字符串字面量、数字字面量、注释、美元引号字符串</span></span>
<span class="line"><span>  → 保留: LIMIT/OFFSET 数字（用于调试）</span></span>
<span class="line"><span>  → 在保护过程中使用 Unicode 私有使用区哨兵</span></span></code></pre></div><h3 id="第-6-层-安全守卫-运行时限制" tabindex="-1">第 6 层：安全守卫（运行时限制） <a class="header-anchor" href="#第-6-层-安全守卫-运行时限制" aria-label="Permalink to &quot;第 6 层：安全守卫（运行时限制）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查询最大结果数:        10,000 行（可配置）</span></span>
<span class="line"><span>深度分页限制:         1,000,000 offset（可配置）</span></span>
<span class="line"><span>批量操作行数:         10,000 行（可配置）</span></span>
<span class="line"><span>IN 子句硬限制:        5,000 参数（可配置）</span></span>
<span class="line"><span>无条件操作:          必须显式传入 allowUnconditional(true)</span></span>
<span class="line"><span>乐观锁重试:           最大 20 次，最大 60 秒总超时</span></span>
<span class="line"><span>递归深度:             NodeResolver=50, CacheKeyBuilder=128</span></span></code></pre></div><h3 id="第-7-层-加密安全-加密" tabindex="-1">第 7 层：加密安全（加密） <a class="header-anchor" href="#第-7-层-加密安全-加密" aria-label="Permalink to &quot;第 7 层：加密安全（加密）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@Encrypt 字段</span></span>
<span class="line"><span>  → 算法: AES/GCM/NoPadding（认证加密，128 位标签）</span></span>
<span class="line"><span>  → 密钥派生: PBKDF2WithHmacSHA256（600,000 次迭代）</span></span>
<span class="line"><span>  → 多版本密钥轮换: v1:key1,v2:key2 格式</span></span>
<span class="line"><span>  → Salt 验证: 生产环境未配置 salt 时阻止运行</span></span>
<span class="line"><span>  → 明文清理: 加密后 Arrays.fill(plaintextBytes, 0)</span></span>
<span class="line"><span>  → 密钥材料清理: PBKDF2 后 Arrays.fill(keyChars, &#39;\\0&#39;)</span></span></code></pre></div><h2 id="线程安全性汇总" tabindex="-1">线程安全性汇总 <a class="header-anchor" href="#线程安全性汇总" aria-label="Permalink to &quot;线程安全性汇总&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>线程安全</th><th>机制</th></tr></thead><tbody><tr><td>QuerySpec</td><td>否</td><td>声明为可变构建器</td></tr><tr><td>SubQuerySpec</td><td>否</td><td>声明为可变构建器</td></tr><tr><td>QueryProjectionSupport</td><td>否</td><td>委托给 QuerySpec（可变构建器）</td></tr><tr><td>EntityGraphHelper</td><td>否</td><td>声明为可变构建器</td></tr><tr><td>FunctionWhitelist</td><td>是</td><td>ConcurrentHashMap + AtomicReference 冻结快照</td></tr><tr><td>SoftDeleteContext</td><td>是</td><td>ThreadLocal&lt;Integer&gt; 计数器</td></tr><tr><td>EntityManagerHelper</td><td>是</td><td>ConcurrentHashMap + volatile 字段</td></tr><tr><td>SoftDeleteBulkExecutor</td><td>是</td><td>无状态（纯静态方法，无共享可变状态）</td></tr><tr><td>QueryCacheManager</td><td>是</td><td>ConcurrentHashMap + ReentrantLock.tryLock()</td></tr><tr><td>DialectDetector</td><td>是</td><td>ConcurrentHashMap 缓存</td></tr><tr><td>EncryptConverter</td><td>是</td><td>ConcurrentLinkedDeque Cipher 对象池（有界，64 容量），borrow/return 原子操作</td></tr><tr><td>InClauseBuilder</td><td>是</td><td>AtomicReference&lt;Config&gt;</td></tr><tr><td>LambdaUtils</td><td>是</td><td>SampledEvictionCache（基于 ConcurrentHashMap）</td></tr><tr><td>IdentifierValidator</td><td>是</td><td>Volatile 标志（仅配置时写入）</td></tr><tr><td>SampledEvictionCache</td><td>是</td><td>ConcurrentHashMap + tryLock 驱逐</td></tr></tbody></table>`,29)])])}const S=n(t,[["render",l]]);export{h as __pageData,S as default};
